// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

import java.io.File;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.QueryEvaluationException;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.Timeout;
import org.junit.jupiter.api.io.TempDir;

/**
 * A COUNT whose true value exceeds {@code Long.MAX_VALUE} must fail loudly instead of silently returning a wrapped
 * number. The dataset is a star join with one hub: one prefix triple plus four independent legs of 65,536 matches each,
 * so the factorized count product is exactly 2^64 — which wraps to 0 in unchecked long arithmetic. No enumerating
 * engine could ever produce this count either (it would need 1.8e19 iterations), so the only honest outcome is a
 * {@link QueryEvaluationException}.
 */
public class LmdbNativeFactorizedOverflowTest {

	private static final String EX = "http://example.com/";
	private static final int LEG_FANOUT = 1 << 16;
	private static final String PARALLEL_FLAG = "rdf4j.lmdb.parallel.enabled";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";

	@TempDir
	File dataDir;

	private SailRepository repository;
	private String previousParallel;

	@BeforeEach
	public void setUp() {
		// keep the query on the sequential factorized-tail path; the parallel strategy shares the same
		// aggregate-state arithmetic and is covered by the same guard
		previousParallel = System.getProperty(PARALLEL_FLAG);
		System.setProperty(PARALLEL_FLAG, "false");

		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI hub = vf.createIRI(EX, "hub");
			conn.begin();
			conn.add(hub, vf.createIRI(EX, "p"), vf.createIRI(EX, "a"));
			IRI[] legs = { vf.createIRI(EX, "q1"), vf.createIRI(EX, "q2"), vf.createIRI(EX, "q3"),
					vf.createIRI(EX, "q4") };
			for (int j = 0; j < LEG_FANOUT; j++) {
				IRI object = vf.createIRI(EX, "o" + j);
				for (IRI leg : legs) {
					conn.add(hub, leg, object);
				}
			}
			conn.commit();
		}
	}

	@AfterEach
	public void tearDown() {
		if (previousParallel == null) {
			System.clearProperty(PARALLEL_FLAG);
		} else {
			System.setProperty(PARALLEL_FLAG, previousParallel);
		}
		repository.shutDown();
	}

	/**
	 * The SELECT path saturates multiplicity instead of erroring: a saturated multiplicity only repeats an identical
	 * row, so every consumable prefix of the stream is exact — under LIMIT the results must match the generic engine.
	 */
	@Test
	public void saturatedMultiplicityUnderLimitMatchesGeneric() {
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s WHERE {\n"
				+ "  ?s ex:p ?a .\n"
				+ "  ?s ex:q1 ?v1 .\n"
				+ "  ?s ex:q2 ?v2 .\n"
				+ "  ?s ex:q3 ?v3 .\n"
				+ "  ?s ex:q4 ?v4 .\n"
				+ "} LIMIT 3";
		List<String> nativeRows = rows(query);
		String previous = System.getProperty(NATIVE_FLAG);
		List<String> genericRows;
		try {
			System.setProperty(NATIVE_FLAG, "false");
			genericRows = rows(query);
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
		assertThat(nativeRows).isEqualTo(genericRows);
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			return QueryResults.asList(conn.prepareTupleQuery(query).evaluate())
					.stream()
					.map(Object::toString)
					.sorted()
					.collect(Collectors.toList());
		}
	}

	@Test
	@Timeout(120) // a gating regression would drop this query onto an enumerating engine that never finishes
	public void countProductOverflowFailsInsteadOfWrapping() {
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s ex:p ?a .\n"
				+ "  ?s ex:q1 ?v1 .\n"
				+ "  ?s ex:q2 ?v2 .\n"
				+ "  ?s ex:q3 ?v3 .\n"
				+ "  ?s ex:q4 ?v4 .\n"
				+ "}";
		assertThatThrownBy(() -> {
			try (SailRepositoryConnection conn = repository.getConnection()) {
				QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			}
		}).isInstanceOf(QueryEvaluationException.class)
				// the message pins that the FACTORIZED path threw — proof the strategy actually engaged
				.hasMessageContaining("factorized aggregation");
	}
}
